(window.webpackJsonp=window.webpackJsonp||[]).push([[736],{1031:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> lengthOfLIS = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">arr</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> longestLens=<span class=\\"hljs-built_in\\">Array</span>(arr.length).fill(<span class=\\"hljs-number\\">1</span>)\\n  <span class=\\"hljs-keyword\\">let</span> preIndex=<span class=\\"hljs-number\\">0</span>,curIndex=<span class=\\"hljs-number\\">1</span>\\n  <span class=\\"hljs-keyword\\">while</span>(curIndex&lt;arr.length){\\n    <span class=\\"hljs-keyword\\">if</span>(arr[curIndex]&gt;arr[preIndex]){\\n      <span class=\\"hljs-keyword\\">let</span> curLen=longestLens[preIndex]+<span class=\\"hljs-number\\">1</span>\\n      longestLens[curIndex]=<span class=\\"hljs-built_in\\">Math</span>.max(longestLens[curIndex],curLen)\\n    }\\n    preIndex++\\n    <span class=\\"hljs-keyword\\">if</span>(preIndex===curIndex){\\n      preIndex=<span class=\\"hljs-number\\">0</span>\\n      curIndex++\\n    }\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> maxLen=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;longestLens.length;i++){\\n    <span class=\\"hljs-keyword\\">if</span>(longestLens[i]&gt;maxLen)maxLen=longestLens[i]\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> maxLen\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">lengthOfLIS</span><span class=\\"hljs-params\\">(self, nums)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type nums: List[int]\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        <span class=\\"hljs-comment\\"># maxLen=0</span>\\n        <span class=\\"hljs-comment\\"># n=len(nums)</span>\\n        <span class=\\"hljs-comment\\"># dp=[1]*n</span>\\n        <span class=\\"hljs-comment\\"># for i in range(n):</span>\\n        <span class=\\"hljs-comment\\">#   cur=nums[i]</span>\\n        <span class=\\"hljs-comment\\">#   for j in range(0,i):</span>\\n        <span class=\\"hljs-comment\\">#     if nums[j]&lt;cur:</span>\\n        <span class=\\"hljs-comment\\">#       dp[i]=max(dp[i],dp[j]+1)</span>\\n        <span class=\\"hljs-comment\\">#   maxLen=max(dp[i],maxLen)</span>\\n        <span class=\\"hljs-comment\\"># return maxLen</span>\\n        \\n        <span class=\\"hljs-comment\\"># O(nlgn)</span>\\n        stack=[]\\n        <span class=\\"hljs-keyword\\">for</span> num <span class=\\"hljs-keyword\\">in</span> nums:\\n          <span class=\\"hljs-keyword\\">if</span> <span class=\\"hljs-keyword\\">not</span> stack <span class=\\"hljs-keyword\\">or</span> stack[<span class=\\"hljs-number\\">-1</span>]&lt;num:\\n            stack.append(num)\\n          <span class=\\"hljs-keyword\\">elif</span> stack[<span class=\\"hljs-number\\">-1</span>]&gt;num:\\n            lo,hi=<span class=\\"hljs-number\\">0</span>,len(stack)<span class=\\"hljs-number\\">-1</span>\\n            <span class=\\"hljs-keyword\\">while</span> lo&lt;hi:\\n              mid=(lo+hi)//<span class=\\"hljs-number\\">2</span>\\n              <span class=\\"hljs-keyword\\">if</span> stack[mid]&lt;num:\\n                lo=mid+<span class=\\"hljs-number\\">1</span>\\n              <span class=\\"hljs-keyword\\">else</span>:\\n                hi=mid\\n            stack[lo]=num\\n        <span class=\\"hljs-keyword\\">return</span> len(stack)\\n</code></pre>\\n"],"titleSlug":"longest-increasing-subsequence","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u8fd9\u9053\u9898\u7528<code>DP</code>\u89e3\u5c31\u662f<code>O(n^2)</code>\u65f6\u95f4\u590d\u6742\u5ea6\u3002</p>\\n<ul>\\n<li>\u521b\u5efa\u4e00\u4e2a<code>dp\u6570\u7ec4</code>\uff0c\u7528\u6765\u50a8\u5b58\u6bcf\u4e2a<code>index</code>\u53ca\u5b83\u4e4b\u524d\u7684\u6700\u957f\u5b50\u5e8f\u5217\uff0c<code>dp[j]</code>\u4f1a\u53bb\u68c0\u67e5\u524d\u9762\u7684\u6bcf\u4e00\u4e2a<code>dp[i]</code>\uff0c\u5982\u679c<code>nums[i]&lt;nums[j]</code>\uff0c\\n\u90a3\u4e48<code>dp[j]=Math.max(dp[j],dp[i]+1)</code>\u3002</li>\\n</ul>\\n<p>\u53e6\u5916\u4e00\u4e2a<code>O(nlgn)</code>\u7684\u65b9\u6cd5\u4e0d\u592a\u5bb9\u6613\u60f3\u5230\uff0c\u9700\u8981\u642d\u5efa\u4e00\u4e2a<code>\u5355\u8c03\u9012\u589e\u6570\u7ec4</code>\u3002</p>\\n<ul>\\n<li>\\n<p>\u7ef4\u62a4\u4e00\u4e2a\u6570\u7ec4<code>stack</code>\uff0c\u5f53<code>stack[-1]</code>\u6bd4\u5f53\u524d<code>nums[i]</code>\u5c0f\u7684\u65f6\u5019\uff0c\u76f4\u63a5<code>append</code>\uff0c\u5982\u679c\u66f4\u5927\uff0c\u9700\u8981\u4e8c\u5206\u641c\u7d22\u5230<code>nums[i]</code>\u5e94\u8be5\u5b58\u5728\u7684\u4f4d\u7f6e\uff0c\\n\u5e76\u4e14\u66ff\u6362\uff0c\u6700\u7ec8<code>stack</code>\u7684\u957f\u5ea6\u5c31\u662f\u6700\u957f\u7ed3\u679c\u3002</p>\\n<p>\u4f8b\u5982<code>[1,3,6,7,9,4,10,5,6]</code></p>\\n<p>\u5f53<code>nums[i]</code>\u4e3a<code>4</code>\u65f6\uff0c<code>stack</code>\u4e3a<code>[1,3,6,7,9]</code>\\n\u5f53<code>nums[i]</code>\u4e3a<code>10</code>\u65f6\uff0c<code>stack</code>\u4e3a<code>[1,3,4,7,9]</code></p>\\n</li>\\n</ul>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4 <code>nums</code> \uff0c\u627e\u5230\u5176\u4e2d\u6700\u957f\u4e25\u683c\u9012\u589e\u5b50\u5e8f\u5217\u7684\u957f\u5ea6\u3002</p>\\n\\n<p>\u5b50\u5e8f\u5217\u662f\u7531\u6570\u7ec4\u6d3e\u751f\u800c\u6765\u7684\u5e8f\u5217\uff0c\u5220\u9664\uff08\u6216\u4e0d\u5220\u9664\uff09\u6570\u7ec4\u4e2d\u7684\u5143\u7d20\u800c\u4e0d\u6539\u53d8\u5176\u4f59\u5143\u7d20\u7684\u987a\u5e8f\u3002\u4f8b\u5982\uff0c<code>[3,6,2,7]</code> \u662f\u6570\u7ec4 <code>[0,3,1,6,2,2,7]</code> \u7684\u5b50\u5e8f\u5217\u3002</p>\\n\xa0\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [10,9,2,5,3,7,101,18]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n<strong>\u89e3\u91ca\uff1a</strong>\u6700\u957f\u9012\u589e\u5b50\u5e8f\u5217\u662f [2,3,7,101]\uff0c\u56e0\u6b64\u957f\u5ea6\u4e3a 4 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [0,1,0,3,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>4\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [7,7,7,7,7,7,7]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 2500</code></li>\\n\\t<li><code>-10<sup>4</sup> <= nums[i] <= 10<sup>4</sup></code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><b>\u8fdb\u9636\uff1a</b></p>\\n\\n<ul>\\n\\t<li>\u4f60\u53ef\u4ee5\u8bbe\u8ba1\u65f6\u95f4\u590d\u6742\u5ea6\u4e3a <code>O(n<sup>2</sup>)</code> \u7684\u89e3\u51b3\u65b9\u6848\u5417\uff1f</li>\\n\\t<li>\u4f60\u80fd\u5c06\u7b97\u6cd5\u7684\u65f6\u95f4\u590d\u6742\u5ea6\u964d\u4f4e\u5230\xa0<code>O(n log(n))</code> \u5417?</li>\\n</ul>\\n","title":"300. \u6700\u957f\u9012\u589e\u5b50\u5e8f\u5217","relatedTags":["\u4e8c\u5206\u67e5\u627e","\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["javascript","python"],"uniqueID":"300"}')}}]);